var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"주먹만으로 침식체들을 전부 해치우다니.","JPN":"拳だけで侵食体を全部やっつけるなんて。","ENG":"She defeated all those C.O.s with just her bare hands.","TWN":"竟然只用拳頭就把侵蝕體全都解決了。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"굉장하시네요, 파티마 씨.","JPN":"すごいですね、ファティマさん。","ENG":"That was amazing, Miss Fatima.","TWN":"法蒂瑪真是了不起……"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"별 말씀을. 브레히트 양의 공중 지원 덕분입니다.","JPN":"とんでもないです。ブレヒトさんの空中支援のおかげです。","ENG":"It was all thanks to your aerial support, Miss Brecht.","TWN":"哪裡的話，多虧了你的空中支援，布萊希特。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"하지만 침식체를 해치워도 침식파 반응은 좀처럼 약해지지 않는군요.","JPN":"ですが、侵食体をやっつけても侵食波の反応は弱くなりませんね。","ENG":"But no matter how many C.O.s we defeat, the Corruption ray response hasn't weakened at all.","TWN":"不過即使擊敗了侵蝕體，侵蝕波反應也依然沒有減弱。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"침식파의 원인이 되는 녀석은 따로 있는 것 같군.","JPN":"侵食波の原因になっているやつは他にいるようだ。","ENG":"It seems that there is something else causing the Corruption ray.","TWN":"看來有另一個傢伙在影響侵蝕波。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"고위 침식파 신호가 둘. 9시와 3시 방향에서 동시에 잡힙니다.","JPN":"高レベルの侵食波信号が2体。9時と3時の方角から同時に感知されます。","ENG":"There are two high-grade Corruption rays coming simultaneously from our 3 and 9 o'clock.","TWN":"捕捉到兩個高階侵蝕波訊號。分別在9點和3點鐘方向。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"둘이요? 그런 걸 동시에 상대하는 건 아무리 파티마 씨라도 무리지 않나요?","JPN":"2体？　それを同時に相手するのは、いくらファティマさんでも無理じゃないですか？","ENG":"Two of them? Won't that be too much for you to handle on your own, Miss Fatima?","TWN":"兩個嗎？即使是法蒂瑪同時對付兩個也太勉強了……？"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"둘 모두 그림자라면, 확실히 번거롭겠군요.","JPN":"両方ともシャドウなら、確かに面倒でしょう。","ENG":"If both are Shadows, then it will definitely be a challenge.","TWN":"如果兩個都是暗影的話，會很麻煩。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"체르노보그.","JPN":"チェルノボーグ。","ENG":"Chernobog.","TWN":"申諾伯。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"처리해.","JPN":"やれ。","ENG":"Take care of it.","TWN":"解決掉。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"9시 방향 900m에 그림자로 추정되는 3종 침식체! 차원균열을 뚫고 이쪽으로 접근 중…!","JPN":"9時の方角、900mにシャドウと推定される第3種侵食体！　次元亀裂を貫いてこちらに接近中……！","ENG":"A Category 3 C.O. presumed to be a Shadow 900 m away at 9 o'clock! It's breaking through the dimensional rift and headed this way...!","TWN":"9點鐘方向900ｍ處，推測為3類侵蝕體的暗影！正穿過次元裂縫向這邊接近……！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"하나는 아직 안 보여요! 저 녀석을 어떻게든 먼저 잡을 수만 있다면…!","JPN":"残り1体はまだ見えません！　あいつを何とか先に倒すことができたら……！","ENG":"I don't see the other one! If we can defeat that one first, then...!","TWN":"我沒有看到另一個！只要能先擊敗這一個的話……！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"어…?","JPN":"え……？","ENG":"Huh...?","TWN":"呃……?"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"제가 뭘 보고 있는 거죠…? 침식체들이 서로 싸우다니.","JPN":"私、何を見てるんでしょう……？　侵食体同志で戦ってるなんて。","ENG":"What am I seeing...? The C.O.s are fighting each other.","TWN":"我看到了什麼……？侵蝕體自己打起來了……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"저도 저런 광경은 처음 봅니다.","JPN":"私もこんな光景は初めてです。","ENG":"I've never seen this before as well.","TWN":"我也是第一次見到這種情況。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"게다가 저 전투의 양상은…","JPN":"それに、あの戦闘の様子は……","ENG":"And the battle...","TWN":"而且戰鬥局面是……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…뒤이어 나타난 인간형 그림자가 일방적으로 몰아붙이고 있군.","JPN":"……後から現われた人間型のシャドウが一方的に追いつめているな。","ENG":"...The Human type Shadow that appeared later is cornering the other like it's nothing.","TWN":"……侵蝕體被之後出現的人形暗影單方面壓制了。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"적어도 3종은 돼 보였는데, 단숨에 해치웠어요.","JPN":"少なくとも第3種に見えたんですけど、一気にやっつけました。","ENG":"It looked to be at least a Category 3, but it was finished off so easily.","TWN":"侵蝕體至少有3類，但卻解決得很輕鬆……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SUMMON_UNION_SHADOW_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"이쪽을 보고 있습니다.","JPN":"こちらを見ています。","ENG":"It's looking this way.","TWN":"它在觀察我們。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"일반적인 그림자라면 카운터를 보고 당장 달려들 텐데, 이상할 정도로 침착하군요.","JPN":"一般的なシャドウならカウンターを見るなり飛びかかってくるはずですが、妙に落ち着いていますね。","ENG":"An ordinary Shadow would've already rushed toward us after seeing a Counter. But this one is strangely calm.","TWN":"如果是普通的暗影，看到制裁者會立刻撲上來，但它卻冷靜得不像話。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}}]`);e